import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function TravelHistory({ employee }) {
  const navigate = useNavigate();
  const apiBase = "https://prasa-app-yde3.onrender.com";

  const empId = employee?.empId || employee?.empld;

  const [travelExpenses, setTravelExpenses] = useState([]);
  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const res = await fetch(
        `${apiBase}/travel-expenses?empId=${encodeURIComponent(empId)}`
      );
      const data = await res.json();
      console.log("TRAVEL RESPONSE:", data);

      setTravelExpenses(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error(err);
      setTravelExpenses([]);
    }
  };

  const clearFilters = () => {
    setFromDate("");
    setToDate("");
    fetchData();
  };

  const filteredData = travelExpenses.filter((item) => {
    const d = new Date(item.travel_date);
    const from = fromDate ? new Date(fromDate) : null;
    const to = toDate ? new Date(toDate) : null;

    if (from && d < from) return false;
    if (to && d > to) return false;
    return true;
  });

  return (
    <div style={outer}>
      <div style={card}>
        <div style={headerRow}>
          <button onClick={() => navigate("/history")} style={backBtn}>←</button>
          <h2 style={title}>Travel Expense History</h2>
        </div>

        <p style={empInfo}>
          Employee: {employee.empName || employee.name} • {empId}
        </p>

        <div style={filterBar}>
          <div>
            <label>From Date</label><br />
            <input
              type="date"
              value={fromDate}
              onChange={(e) => setFromDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <div>
            <label>To Date</label><br />
            <input
              type="date"
              value={toDate}
              onChange={(e) => setToDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <button onClick={clearFilters} style={clearBtn}>Clear</button>
        </div>

        <table style={table}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>From</th>
              <th>To</th>
              <th>Amount</th>
            </tr>
          </thead>
          <tbody>
            {filteredData.length === 0 ? (
              <tr>
                <td colSpan="5" style={noData}>No travel records found.</td>
              </tr>
            ) : (
              filteredData.map((item) => (
                <tr key={item.id}>
                  <td>{item.travel_date}</td>
                  <td>{item.purpose}</td>
                  <td>{item.location_from}</td>
                  <td>{item.location_to}</td>
                  <td>₹{item.amount}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>

      </div>
    </div>
  );
}

export default TravelHistory;

/* ---------- STYLES ---------- */
const outer = { width:"100%", minHeight:"100vh", background:"#f5faf7", padding:"20px" };
const card = { background:"#fff", padding:"20px", borderRadius:"12px", boxShadow:"0 2px 10px rgba(0,0,0,0.05)" };
const headerRow = { display:"flex", alignItems:"center", gap:"10px" };
const backBtn = { background:"transparent", border:"none", fontSize:"20px", cursor:"pointer", color:"#0f9d58" };
const title = { fontSize:"22px", fontWeight:"600", color:"#0f9d58" };
const empInfo = { color:"#666", marginTop:"-5px" };
const filterBar = { display:"flex", gap:"20px", background:"#eaf8f0", padding:"12px", borderRadius:"10px", marginTop:"10px" };
const filterInput = { padding:"6px 10px", borderRadius:"5px", border:"1px solid #ccc" };
const clearBtn = { background:"#ff5252", color:"#fff", border:"none", padding:"8px 16px", borderRadius:"6px", cursor:"pointer" };
const table = { width:"100%", marginTop:"15px", borderCollapse:"collapse" };
const noData = { textAlign:"center", padding:"20px", color:"#777" };
